import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_waiting_time(available_time, current_time):
        return max(0, available_time - current_time)

    best_node = None
    min_total_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = calculate_distance(cur_truck_pos, customer_pos)
        arrival_time = current_time + distance_to_customer / truck_speed
        time_window_start, time_window_end = time_windows[i]
        waiting_time = calculate_waiting_time(time_window_start, arrival_time)

        total_time = arrival_time + waiting_time

        if total_time < min_total_time:
            min_total_time = total_time
            best_node = i

    return best_node
